evals.prompt:
Tenho esse flow com erros no validator, corrija todos:

```json
{
  "version": "7.3",
  "screens": [
    {
      "id": "CADASTRO",
      "title": "Seus dados",
      "data": {
        "estados": {
          "type": "array",
          "items": { "type": "object" },
          "__example__": [{"id": "sp", "title": "São Paulo"}]
        }
      },
      "layout": {
        "type": "SingleColumnLayout",
        "children": [
          {
            "type": "TextInput",
            "name": "email",
            "label": "E-mail",
            "input-type": "email",
            "min-chars": "3",
            "max-chars": "80",
            "required": true
          },
          {
            "type": "Dropdown",
            "name": "estado",
            "label": "Estado",
            "data-source": "${data.estados}",
            "required": true
          },
          {
            "type": "Footer",
            "label": "Continuar",
            "on-click-action": {
              "name": "navigate",
              "next": { "type": "screen", "name": "CONFIRMACAO" },
              "payload": { "email": "${form.email}", "estado": "${form.estado}" }
            }
          }
        ]
      }
    },
    {
      "id": "CONFIRMACAO",
      "terminal": true,
      "data": {
        "email": { "type": "string", "__example__": "" },
        "estado": { "type": "string", "__example__": "" }
      },
      "layout": {
        "type": "SingleColumnLayout",
        "children": [
          { "type": "TextBody", "text": "`'E-mail: ' ${data.email}`" },
          { "type": "TextBody", "text": "`'Estado: ' ${data.estado}`" },
          {
            "type": "Footer",
            "label": "Confirmar",
            "on-click-action": {
              "name": "navigate",
              "next": { "type": "screen", "name": "CONFIRMACAO" },
              "payload": {}
            }
          }
        ]
      }
    }
  ]
}
```
